        context.setVariable("metadata", Map.of("city", "Seoul", "year", 2020, "country", "BG"));
        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));
    }

    @Test
    public void testGroup() {
        String vectorExpr = this.converter.convertExpression(new Filter.Expression(AND, new Filter.Group(new Filter.Expression(OR, new Filter.Expression(GTE, new Filter.Key("year"), new Filter.Value(2020)), new Filter.Expression(EQ, new Filter.Key("country"), new Filter.Value("BG")))), new Filter.Expression(NIN, new Filter.Key("city"), new Filter.Value(List.of("Sofia", "Plovdiv")))));
        assertThat(vectorExpr).isEqualTo("(#metadata['year'] >= 2020 or #metadata['country'] == 'BG') and not {'Sofia','Plovdiv'}.contains(#metadata['city'])");
        StandardEvaluationContext context = new StandardEvaluationContext();
        ExpressionParser parser = new SpelExpressionParser();
        context.setVariable("metadata", Map.of("city", "Seoul", "year", 2020, "country", "BG"));
